export class DefaultReplicationPlugin implements ReplicationPlugin {
  name: string = 'default-replication-plugin';
  private internalDb!: InternalDatabase;
  private externalDbClient!: ExternalDBClient;
  private config!: ReplicationTaskConfig;
  private lastReplicationTimestamps: Map<string, Date> = new Map(); // To track last pull time per table

  async initialize(
    internalDb: InternalDatabase,
    externalDbConfig: ExternalDatabaseConfig,
    config: ReplicationTaskConfig
  ): Promise<void> {
    this.internalDb = internalDb;
    this.config = config;
    // Replace MockExternalDBClient with a real client for your external database
    this.externalDbClient = new MockExternalDBClient(externalDbConfig.url);
    await this.externalDbClient.connect();
    console.log(`Replication plugin '${this.name}' initialized for task: ${JSON.stringify(config)}`);
  }

  async replicate(): Promise<void> {
    console.log(`Starting replication for plugin '${this.name}'...`);
    for (const tableConfig of this.config.tables) {
      await this.replicateTable(tableConfig);
    }
    console.log(`Replication for plugin '${this.name}' finished.`);
  }

  private async replicateTable(tableConfig: TableReplicationConfig): Promise<void> {
    console.log(`Replicating table: ${tableConfig.externalTableName} -> ${tableConfig.name}`);
    try {
      let externalData: any[];
      const lastTimestamp = this.lastReplicationTimestamps.get(tableConfig.name);

      if (tableConfig.trackingColumn && lastTimestamp) {
        // Incremental replication
        const query = `SELECT * FROM ${tableConfig.externalTableName} WHERE ${tableConfig.trackingColumn} > $1 ORDER BY ${tableConfig.trackingColumn} ASC`;
        externalData = await this.externalDbClient.query(query, [lastTimestamp.toISOString()]);
        console.log(`Incremental pull for ${tableConfig.name}: found ${externalData.length} new/updated records since ${lastTimestamp.toISOString()}`);
      } else {
        // Full replication (or first run)
        const query = `SELECT * FROM ${tableConfig.externalTableName}`;
        externalData = await this.externalDbClient.query(query);
        console.log(`Full pull for ${tableConfig.name}: found ${externalData.length} records`);
      }

      if (externalData.length > 0) {
        await this.upsertData(tableConfig, externalData);
        // Update last replication timestamp
        const latestTimestamp = externalData.reduce((max, row) => {
          if (tableConfig.trackingColumn && row[tableConfig.trackingColumn]) {
            const rowDate = new Date(row[tableConfig.trackingColumn]);
            return rowDate > max ? rowDate : max;
          }
          return max;
        }, lastTimestamp || new Date(0)); // Initialize with epoch if no previous timestamp
        this.lastReplicationTimestamps.set(tableConfig.name, latestTimestamp);
      }
    } catch (error) {
      console.error(`Error replicating table ${tableConfig.name}:`, error);
    }
  }

  private async upsertData(tableConfig: TableReplicationConfig, data: any[]): Promise<void> {
    if (data.length === 0) return;

    const columns = Object.keys(data[0]);
    const placeholders = columns.map((_, i) => `?`).join(', ');
    const updateAssignments = columns.filter(col => col !== tableConfig.primaryKey).map(col => `${col} = EXCLUDED.${col}`).join(', ');

    // Create table if it doesn't exist (simplified, real implementation would check schema and types)
    const createTableSql = `CREATE TABLE IF NOT EXISTS ${tableConfig.name} (${columns.map(col => `${col} TEXT`).join(', ')}, PRIMARY KEY (${tableConfig.primaryKey}))`;
    await this.internalDb.execute(createTableSql);

    const insertSql = `
      INSERT INTO ${tableConfig.name} (${columns.join(', ')})
      VALUES (${placeholders})
      ON CONFLICT(${tableConfig.primaryKey}) DO UPDATE SET
        ${updateAssignments};
    `;

    for (const row of data) {
      const values = columns.map(col => row[col]);
      await this.internalDb.execute(insertSql, values);
    }
    console.log(`Upserted ${data.length} records into internal table ${tableConfig.name}`);
  }

  async destroy?(): Promise<void> {
    if (this.externalDbClient) {
      await this.externalDbClient.disconnect();
    }
    console.log(`Replication plugin '${this.name}' destroyed.`);
  }
}
